			/* Стили для ссылок в раскрывашках плашек в Отраслях */

.solved-tasks__title a {
  color: inherit;
  text-decoration: none;
  transition: opacity 0.15s ease-out;
}

.solved-tasks__info__description a {
  color: #1388ca;
  text-decoration: none;
  transition: opacity 0.15s ease-out;
}

.solved-tasks__title a:hover,
.solved-tasks__info__description a:hover {
  opacity: 0.7;
}

/* Стили для цитаты в Отраслях */

body.single-industries .solved-tasks + .customer-quote {
  background-color: #ecf2f7;
}

@media screen and (min-width: 743px) {
  body.single-industries .solved-tasks + .customer-quote {
    padding-bottom: 20px;
  }
}

/* Фикс для размера картинки в "Какие задачи решает..." в Отраслях на Табе */

@media screen and (min-width: 743px) and (max-width: 1234.5px) {
  body.single-industries .solved-tasks__image {
    width: 160px;
  }
